import click
import json
from pathlib import Path

@click.command()
@click.option("--config", "-c", default="config.json",
              help="Configuration file")
def run(config):
    """Run with config file"""
    config_path = Path(config)
    if config_path.exists():
        cfg = json.load(config_path.open())
        click.echo(f"Loaded config: {cfg}")
    else:
        click.echo("No config found, using defaults")
